import {useState} from "react";
import {askAI} from "../services/api";
import Message from "./Message";

export default function ChatBox(){

  const[messages,setMessages]=useState([]);
  const[question,setQuestion]=useState("");
  const[loading,setLoading]=useState(false);

  const send=async()=>{

    if(!question) return;

    const userMsg={type:"user",text:question};

    setMessages(prev=>[...prev,userMsg]);

    setLoading(true);

    try{

      const res=await askAI(question);

      const aiMsg={
        type:"ai",
        text:res.data.answer
      };

      setMessages(prev=>[...prev,aiMsg]);

    }catch(err){

      setMessages(prev=>[
        ...prev,
        {type:"ai",text:"⚠ Error getting response"}
      ]);

    }

    setLoading(false);
    setQuestion("");

  };

  return(

    <div style={{
      display:"flex",
      flexDirection:"column",
      height:"100%",
      background:"#f3f4f6"
    }}>

      <div style={{
        flex:1,
        overflowY:"auto",
        padding:"10px"
      }}>

        {messages.map((m,i)=>(
          <Message key={i} msg={m}/>
        ))}

        {loading && <p>AI thinking...</p>}

      </div>

      <div style={{
        display:"flex",
        gap:"10px",
        padding:"10px",
        background:"white"
      }}>

        <input
          value={question}
          onChange={(e)=>setQuestion(e.target.value)}
          placeholder="Ask question from your PDF..."
          style={{
            flex:1,
            padding:"10px",
            borderRadius:"6px",
            border:"1px solid #ccc"
          }}
        />

        <button
          onClick={send}
          style={{
            background:"#8b5cf6",
            color:"white",
            border:"none",
            padding:"10px 15px",
            borderRadius:"6px",
            cursor:"pointer"
          }}
        >
          Ask
        </button>

      </div>

    </div>

  );

}
